ruleContent.content:
@js:
let json = JSON.parse(result);
let images = json.data.info.images.images; // 定位到 JSON 中的图片数组
let imgTags = [];

// 如果 JSON 没带域名前缀，包子漫画 V3 接口的默认主域名通常是下方这个
let host = json.data.info.domain || "https://f40-1-4.g-mh.online"; 

for (let i = 0; i < images.length; i++) {
    let imgUrl = images[i].url;
    // 有些接口返回的是绝对路径，有些是相对路径，要做个兼容判断
    if (!imgUrl.startsWith("http")) {
        imgUrl = host + imgUrl;
    }
    imgTags.push('<img src="' + imgUrl + '">');
}

// 用换行符拼接所有 img 标签，交给底层阅读引擎排版渲染
imgTags.join('\n');

