ruleContent.content:
$.data
<js>
function cleanChapterText(text) {
  const lines = text.split('\n');
  const filteredLines = lines.filter(line => {
    return !(line.includes('第') && line.includes('章')) && 
           !line.includes('作者：') &&
           !/^\d{4}-\d{2}-\d{2}/.test(line.trim());
  });
  return filteredLines.join('\n');
}

cleanChapterText(result);
</js>

ruleContent.imageDecode:
function decode(bytes, key, iv) {
    return java.createSymmetricCrypto("aes/cbc/pkcs7padding", key, iv).decrypt(bytes);
}
if (/cpx=/.test(src)) {
    let cpx = src.match(/cpx=(.+?)&token/)[1];
    let iv = java.base64Decode(decodeURIComponent(cpx)).substring(60, 76);
    let data_length = parseInt(java.bytesToStr(result.slice(1, 5)));
    let key = result.slice(data_length + 5);
    let content = result.slice(5, data_length + 5);
    let head = decode(content.slice(0, 20496), key, iv);
    result = Buffer.concat([head, content.slice(20496)]);
    result;
} else {
    result;
}

loginCheckJs:
var res = result;
url = java.ruleUrl;
if(res.body().includes('人机验证')){
    cookie.removeCookie(Get('url'));
    result = java.startBrowserAwait(url,"验证");
}
if(res.body().includes('need login')){
    eval(String(source.loginUrl));
    cookie.removeCookie(Get('url'));
    Login();
    result = java.connect(url);
}
if(res.body().includes('稍后重试')){
    cookie.removeCookie(Get('url'));
    java.webView('', Get('url'), '');
    sleep(5000);
    result = java.connect(url);
}
result;

