function login() {}
var loginInfo = source.getLoginInfoMap() || {};
var isAuth = false;
var defaultUrl = '';
try {
defaultUrl = verify();
isAuth = true;
} catch(e) {
isAuth = false;
}
var urlInput = '';
if (isAuth) {
urlInput = loginInfo['当前网址选择'];
if (urlInput == '') {
urlInput = defaultUrl;
}
}
var pageInput = '';
if (isAuth) {
pageInput = loginInfo['发现起始页'];
if (pageInput == '') {
pageInput = '1';
}
}
var tagValue = 'closed';
if (isAuth) {
tagValue = getTag();
}
loginInfo['当前网址选择'] = urlInput;
loginInfo['发现起始页'] = pageInput;
source.putLoginInfo(JSON.stringify(loginInfo));
var varData = {
"tag": tagValue,
"page": pageInput,
"url": urlInput
};
source.setVariable(JSON.stringify(varData,null,2));
function showStatus() {
try {
var url = getUrl();
var page = getPage() + 1;
var tag = getTag();
var tagText = (tag === 'closed') ? "已关闭" : "【" + tag + "】";
java.longToast(
"\n" + "======================" + "\n🔑 状态: ✅ 已激活\n" +
"⋮ ⋮" + "\n" +
"🏷️ 标签: " + tagText + "\n" +
"⋮ ⋮" + "\n" +
"📚 起始页: " + page + "\n" +
"⋮ ⋮" + "\n" +
"🌐 " + url +"\n" + "======================="
);
} catch (e) {
}
}
function kk() {
var tag = getData().tag;
java.toast((tag === 'closed') ? '\n👤 标签已关闭' : '\n👤 已选标签【 ' + tag + ' 】');
}
function testSpeed() {
var url = getUrl();
java.toast("\n⏰ 开始测试延迟");
try {
var start = new Date().getTime();
java.ajax(url);
var time = new Date().getTime() - start;
var sec = (time / 1000).toFixed(2);
var text, icon;
if (time < 300) { text = "极快"; icon = "🚀"; }
else if (time < 600) { text = "快速"; icon = "👍"; }
else if (time < 1000) { text = "良好"; icon = "👌"; }
else if (time < 2000) { text = "稍慢"; icon = "💡"; }
else if (time < 5000) { text = "较慢"; icon = "🐢"; }
else { text = "很慢"; icon = "⏳"; }
java.longToast("『…………………………………………" + "\n" + icon + " " + text + "  |  耗时: " + sec + "秒" + "\n" + "⋮ ⋮" + "\n" + "🌐 " + url + "\n" + "⋮ ⋮" + "\n" + "注：结果受多种因素影响，仅供参考" + "\n" +"……………………………………………』");
} catch (e) {
}
}
function selectLetter(letter) {
try {
setTag(letter);
java.toast(letter === 'closed' ? "❎ 已关闭标签" : "🏷️ 已选: " + letter);
} catch (e) {
}
}
function openWeb() {
try {
var url = getUrl();
java.startBrowser(url, url);
java.toast('\n🌐 ' + url);
} catch (e) {
}
}
function publish() {
try {
getUrl();
var url1 = getUrl1();
java.longToast("\n⏳ 正在加载中...请耐心等待~");
var html = getPublishHtml();
java.startBrowser(url1, '最新网址',html);
} catch(e) {
}
}
function Author() {
var url = getAuthor();
java.openUrl(url);
}

