function getData() {
var data = this.source.getVariable();
if (!data) return {};
try { return JSON.parse(String(data)); }
catch(e) { return {}; }
}
function setData(data) {
this.source.setVariable(JSON.stringify(data));
}
function getKey() {
var loginInfo = this.source.getLoginInfoMap();
var author = loginInfo && loginInfo.get('源作者');
if (!author || author.trim() == '') return null;
return this.java.md5Encode16(author);
}
function decrypt(code) {
var key = getKey.call(this);
if (!key) return null;
try {
return this.java.createSymmetricCrypto("AES", key).decryptStr(code);
} catch(e) {
return null;
}
}
function getCom() {
return this.source.bookSourceComment || '';
}
function getName() {
return this.source.bookSourceName || '';
}
function verifyComment() {
var keyword = decrypt.call(this, cm);
if (!keyword) return false;
return getCom.call(this).includes(keyword);
}
function verifyName() {
var keyword = decrypt.call(this, bn);
if (!keyword) return false;
return getName.call(this).includes(keyword);
}
function verifySource() {
return verifyComment.call(this) && verifyName.call(this);
}
function verify() {
var defaultUrl = decrypt.call(this, eu);
if (!defaultUrl) {
var tip = "\n===================\n❌ 激 活 失 败~\n✍🏻 请输入正确的源作者\n===================\n";
this.java.longToast(tip);
throw new Error(tip);
}
if (!verifySource.call(this)) {
var tip = "\n============\n❌  校  验  失  败 ~\n🥺 检测到源被修改\n============\n";
this.java.longToast(tip);
throw new Error(tip);
}
return String(defaultUrl).replace(/\/$/, '');
}
function getUrl() {
var defaultUrl = verify.call(this);
var data = getData.call(this);
var customUrl = data.url;
if (customUrl && customUrl.trim() != '' && customUrl != defaultUrl) {
return String(customUrl).replace(/\/$/, '');
}
return defaultUrl;
}
function getPage() {
verify.call(this);
var data = getData.call(this);
return data.page ? parseInt(data.page) - 1 : 0;
}
function getTag() {
verify.call(this);
var data = getData.call(this);
return data.tag || 'closed';
}
function setTag(tag) {
var data = getData.call(this);
try {
verify.call(this);
data.tag = tag || 'closed';
} catch(e) {
data.tag = 'closed';
setData.call(this, data);
throw e;
}
setData.call(this, data);
return data.tag;
}
function getUrl1() {
return 'https://diyibanzhu.app';
}
function getAuthor() {
return 'https://ycoo.net/home.php?mod=space&uid=20609&do=thread&view=me&type=thread&from=space&mobile=2';
}
function evalSearch() {
var base = getUrl.call(this);
var path = decrypt.call(this, sc);
if (!path) throw new Error("搜索解密失败");
return base + path;
}
function evalContent(src, baseUrl, book, chapter) {
verify.call(this);
var code = decrypt.call(this, cc);
if (!code) throw new Error("正文解密失败");
code = String(code).replace(/^\s*<js>\s*/i, '').replace(/\s*<\/js>\s*$/i, '');
var java = this.java;
var result = '';
return eval(code);
